const body = $json.body ?? $json;
const headers = $json.headers ?? {};
const authHeader = headers.authorization || headers.Authorization || '';
const bearerSecret = authHeader.startsWith('Bearer ') ? authHeader.slice(7) : '';
const providedSecret = body.secret || bearerSecret || '';
const expectedSecret = '';
if (expectedSecret && providedSecret !== expectedSecret) {
  return [{ json: { success: false, error: 'unauthorized' } }];
}

const baseUrl = 'https://n8n-dev.noyecode.com';
const projectId = 'bkrM241Q8UeW2zme';
const tableId = 'LFM69EeeF7pa8yiO';
const browserId = 'bot-job-enqueue';
const loginPayload = {
  emailOrLdapLoginId: 'andersonbarbosadev@outlook.com',
  password: 't5x]oIs{7=ISZ}sS',
};

const action = String(body.action || 'run_full_cycle').trim() || 'run_full_cycle';
const payload = body.payload && typeof body.payload === 'object' ? body.payload : {};
const source = String(body.source || 'telegram').trim() || 'telegram';
const nowIso = new Date().toISOString();
const jobId = `job_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

const normalizeCookies = (rawCookieHeader) => {
  if (!rawCookieHeader) return [];
  if (Array.isArray(rawCookieHeader)) return rawCookieHeader.map((item) => String(item).split(';')[0]).filter(Boolean);
  return String(rawCookieHeader).split(',').map((item) => item.split(';')[0].trim()).filter(Boolean);
};

try {
  const request = this.helpers.request;
  const loginResponse = await request({
    method: 'POST',
    uri: `${baseUrl}/rest/login`,
    body: loginPayload,
    json: true,
    resolveWithFullResponse: true,
    simple: false,
    headers: {
      Accept: 'application/json',
      'browser-id': browserId,
      'User-Agent': 'n8n-bot-job-queue/1.0',
    },
  });

  const cookies = normalizeCookies(loginResponse?.headers?.['set-cookie']);
  if (!cookies.length) {
    return [{ json: { success: false, error: 'login_cookie_missing' } }];
  }

  const inserted = await request({
    method: 'POST',
    uri: `${baseUrl}/rest/projects/${projectId}/data-tables/${tableId}/insert`,
    body: {
      returnType: 'all',
      data: [
        {
          job_id: jobId,
          action,
          payload_json: JSON.stringify(payload),
          source,
          status: 'pending',
          created_at: nowIso,
          updated_at: nowIso,
          worker_id: '',
          attempts: 0,
          lease_expires_at: '',
          result_json: '',
          error_text: '',
        },
      ],
    },
    json: true,
    resolveWithFullResponse: true,
    simple: false,
    headers: {
      Accept: 'application/json',
      Cookie: cookies.join('; '),
      'browser-id': browserId,
      'User-Agent': 'n8n-bot-job-queue/1.0',
    },
  });

  const row = Array.isArray(inserted?.body?.data) ? inserted.body.data[0] : inserted?.body?.data?.[0] || {};
  return [{
    json: {
      success: true,
      enqueued: true,
      job: {
        id: jobId,
        row_id: row?.id ?? null,
        action,
        payload,
        source,
        status: 'pending',
        createdAt: nowIso,
        updatedAt: nowIso,
      },
      activeJobs: null,
    },
  }];
} catch (error) {
  return [{ json: { success: false, error: String(error?.message || error) } }];
}

const body = $json.body ?? $json;
const headers = $json.headers ?? {};
const authHeader = headers.authorization || headers.Authorization || '';
const bearerSecret = authHeader.startsWith('Bearer ') ? authHeader.slice(7) : '';
const providedSecret = body.secret || bearerSecret || '';
const expectedSecret = $env.N8N_BOT_SECRET || '';
if (expectedSecret && providedSecret !== expectedSecret) {
  return [{ json: { success: false, error: 'unauthorized' } }];
}

const workerId = body.worker_id || body.workerId || 'worker-local';
const leaseMinutes = Number(body.lease_minutes || body.leaseMinutes || 5);
const now = Date.now();
const nowIso = new Date(now).toISOString();
const state = $getWorkflowStaticData('global');
state.jobs = Array.isArray(state.jobs) ? state.jobs : [];

for (const item of state.jobs) {
  if (item.status === 'dispatched' && item.leaseExpiresAt) {
    const expiresAt = Date.parse(item.leaseExpiresAt);
    if (!Number.isNaN(expiresAt) && expiresAt < now) {
      item.status = 'pending';
      item.workerId = null;
      item.leaseExpiresAt = null;
      item.updatedAt = nowIso;
    }
  }
}

const job = state.jobs.find((item) => item.status === 'pending');
if (!job) {
  return [{ json: { success: true, found: false } }];
}

job.status = 'dispatched';
job.workerId = workerId;
job.attempts = Number(job.attempts || 0) + 1;
job.updatedAt = nowIso;
job.leaseExpiresAt = new Date(now + leaseMinutes * 60 * 1000).toISOString();

return [{ json: { success: true, found: true, job } }];

